
@set current_month = 202603
@set paid_thru = 202602
@set notifications_date = 04012026

-- Therapy mm table
select 	
	fin_inc_month
	, sgr_source_name
	, count(distinct fin_mbi_hicn_fnl)
from tmp_1q.kn_mbm_dtl_${current_month}
where fin_inc_month in ('202509', '202601')
group by 1, 2
order by 1
;

